#include <iostream>#include <vector>#include <algorithm>#include <queue>#include <map>#include <set>#include <unordered_map>#include <unordered_set>#include <stack>#include <cmath>#include <cstring> using namespace std; // Type aliasesusing ll = long long;using ld = long double;using vi = vector<ll>;using pii = pair<ll, ll>; // Priority queues#define que_max priority_queue<ll>#define que_min priority_queue<ll, vector<ll>, greater<ll>> // Debugging#define bug(...) __f(#__VA_ARGS__, __VA_ARGS__) template <typename Arg1>void __f(const char* name, Arg1&& arg1) {    cout << name << " : " << arg1 << endl;} template <typename Arg1, typename... Args>void __f(const char* names, Arg1&& arg1, Args&&... args) {    const char* comma = strchr(names + 1, ',');    cout.write(names, comma - names) << " : " << arg1 << " | ";    __f(comma + 1, args...);} // Printing helpers#define print(a) for (auto x : a) cout << x << " "; cout << endl#define print1(a) for (auto x : a) cout << x.first << " " << x.second << endl#define print2(a,x,y) for (int i = x; i < y; i++) cout << a[i] << " "; cout << endl void solve() {    int n, k;    cin >> n >> k;    vector<int> a(n);    for(int i = 0; i < n; i++) {        cin >> a[i];    }     bool is_sorted = true;    for(int i = 0; i < n-1; i++) {        if(a[i] > a[i+1]) {            is_sorted = false;            break;        }    }     if(k == 1 && !is_sorted) {        cout << "NO" << endl;        return;    }     cout << "YES" << endl;} int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);     int t = 1;    cin >> t;    while (t--) solve();     return 0;}